private enum TeamsScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("réunion") || t.contains("meeting") || t.contains("calendar") || t.contains("activity"):
            TeamsMeetingsScreen()
        case let t where t.contains("chat") || t.contains("team"):
            TeamsTeamChatScreen()
        default:
            TeamsGenericListScreen(title: tab)
        }
    }
}
